DROP TABLE IF EXISTS src_store_detail CASCADE;

CREATE TABLE src_store_detail (
    store_code          TEXT,
    store_description   TEXT,
    country             TEXT,
    area                TEXT,
    city                TEXT,
    district            TEXT,
    zip                 TEXT,
    channel_type        TEXT,
    gross_area          NUMERIC,
    net_sales_area      NUMERIC,
    area_unit           TEXT,
    latitude            TEXT,
    longitude           TEXT,
    opening_date        DATE,
    closing_date        DATE,
    local_currency      TEXT,
    format              TEXT,
    building_type       TEXT,
    chain               TEXT,
    class               TEXT,
    segment             TEXT,
    partition_time      DATE
);

